"use client";

import { useState } from "react";

export default function RegisterPage() {
  const [form, setForm] = useState({
    name: "",
    phone: "",
    role: "PATIENT",
    age: "",
    gender: "",
    address: "",
  });

  const handleChange = (e: any) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleRegister = async () => {
    try {
      const res = await fetch("http://localhost:5000/api/auth/register", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          ...form,
          age: Number(form.age),
        }),
      });

      const data = await res.json();

      localStorage.setItem("token", data.token);

      alert("Registration successful");
    } catch (error) {
      console.error(error);
      alert("Registration failed");
    }
  };

  return (
    <div className="flex h-screen items-center justify-center bg-gray-100">
      <div className="bg-white p-6 rounded-xl shadow-md w-[400px]">
        <h2 className="text-xl font-semibold mb-4">Register</h2>

        <input name="name" placeholder="Name" onChange={handleChange} className="input" />
        <input name="phone" placeholder="Phone" onChange={handleChange} className="input" />

        <select name="role" onChange={handleChange} className="input">
          <option value="PATIENT">Patient</option>
          <option value="DOCTOR">Doctor</option>
        </select>

        {form.role === "PATIENT" && (
          <>
            <input name="age" placeholder="Age" onChange={handleChange} className="input" />
            <input name="gender" placeholder="Gender" onChange={handleChange} className="input" />
            <input name="address" placeholder="Address" onChange={handleChange} className="input" />
          </>
        )}

        <button
          onClick={handleRegister}
          className="w-full bg-green-600 text-white py-2 rounded mt-3"
        >
          Register
        </button>
      </div>
    </div>
  );
}